import sys
from functools import lru_cache

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    a_set = set(a)

    def check(b):
        diffs = set(x - y for x in b for y in b)
        return a_set.issubset(diffs)

    visited = set()

    def backtrack(b):
        key = frozenset(b)
        if key in visited:
            return False
        visited.add(key)

        if check(b):
            return True
        if len(b) >= n:
            return False

        # Find first uncovered a_i
        diffs = set(x - y for x in b for y in b)
        uncovered = None
        for v in a:
            if v not in diffs:
                uncovered = v
                break

        if uncovered is None:
            return True

        v = uncovered
        candidates = set()
        for e in b:
            candidates.add(e + v)  # new - e = v => new = e + v
            candidates.add(e - v)  # e - new = v => new = e - v

        for c in sorted(candidates):
            new_b = tuple(sorted(b + (c,)))
            new_key = frozenset(new_b)
            if new_key not in visited:
                if backtrack(new_b):
                    return True

        return False

    if backtrack((0,)):
        print("YES")
    else:
        print("NO")

